163邮箱邮件发送 代码链接：https://pan.wo.cn/s/1J1c4w90901 提取码：1Spc 参考博客：https://developer.huawei.com/consumer/cn/blog/topic/03148160059378015 在module.json5配置文件加上对权限的声明： &quot;requestPermissions&quot;: [ &#123; &quot;name&quot;: &quot;ohos.permission.INTERNET&quot; &#125;] // 导入所需的模块import socket from &#x27;@ohos.net.socket&#x27;; // 网络套接字模块，用于TCP/TLS通信import util from &#x27;@ohos.util&#x27;; // 工具模块，用于Base64编码/解码等// 接口定义interface LocalAddress &#123; address: string; // 本地绑定地址 family: number; // 地址族（IPv4=1, IPv6=2）&#125;interface ServerAddress &#123; address: string; // 服务器地址 port: number; // 服务器端口 family: number; // 地址族&#125;interface MessageValue &#123; message: ArrayBuffer; // 接收到的消息数据（二进制格式）&#125;interface SecureOptions &#123; protocols: socket.Protocol[]; // 支持的TLS协议版本 cipherSuite: string; // 加密套件配置&#125;interface ConnectOptions &#123; address: ServerAddress; // 服务器地址信息 secureOptions: SecureOptions; // TLS安全选项&#125;// 全局TLSSocket实例let tlsSocket: socket.TLSSocket | null = null;@Entry@Componentstruct Index &#123; bindLocal: boolean = false // Socket是否已绑定本地地址 isServerResponse: boolean = false // 是否收到服务器响应 @State serverAddr: string = &quot;smtp.163.com&quot; // SMTP服务器地址 @State serverPort: number = 465 // SMTP TLS端口 @State userName: string = &quot;staseaiot@163.com&quot; // 邮箱用户名 @State passwd: string = &quot;DAtTEFxcvXt76ByV&quot; // 邮箱授权码（不是登录密码） @State rcptList: string = &quot;1970884166@qq.com&quot; // 收件人列表（逗号分隔） @State mailTitle: string = &quot;意见反馈&quot; // 邮件标题 @State mailFrom: string = &quot;staseaiot@163.com&quot; // 发件人邮箱 @State mailContent: string = &quot;This is greeting from Harmony OS&quot; // 邮件内容 @State canSend: boolean = false // 是否可以发送邮件（登录成功后设为true） // UI构建函数 build() &#123; Row() &#123; Column() &#123; Text(&quot;邮件发送客户端（163邮箱 - 465 TLS）&quot;) .fontSize(14) .fontWeight(FontWeight.Bold) .width(&#x27;100%&#x27;) .textAlign(TextAlign.Center) .padding(10) // 服务器地址输入 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;邮箱服务器地址：&quot;) .width(120) .fontSize(14) .flexGrow(0) TextInput(&#123; text: this.serverAddr &#125;) .onChange((value) =&gt; &#123; this.serverAddr = value &#125;) .width(110) .fontSize(12) .flexGrow(1) &#125;.width(&#x27;100%&#x27;).padding(5) // 服务器端口输入 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;邮箱服务器端口：&quot;) .width(120) .fontSize(14) .flexGrow(0) TextInput(&#123; text: this.serverPort.toString() &#125;) .type(InputType.Number) .onChange((value) =&gt; &#123; this.serverPort = parseInt(value) &#125;) .width(110) .fontSize(12) .flexGrow(1) &#125;.width(&#x27;100%&#x27;).padding(5) // 用户名输入 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;邮箱用户名：&quot;) .width(90) .fontSize(14) .flexGrow(0) TextInput(&#123; text: this.userName &#125;) .onChange((value) =&gt; &#123; this.userName = value &#125;) .width(110) .fontSize(12) .flexGrow(1) &#125;.width(&#x27;100%&#x27;).padding(5) // 密码输入和登录按钮 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;登录密码(授权码)：&quot;) .width(130) .fontSize(14) .flexGrow(0) TextInput(&#123; text: this.passwd &#125;) .onChange((value) =&gt; &#123; this.passwd = value &#125;) .width(100) .fontSize(12) .flexGrow(1) Button(&quot;登录&quot;) .onClick(() =&gt; &#123; this.login() &#125;) .width(70) .fontSize(14) .flexGrow(0) &#125;.width(&#x27;100%&#x27;).padding(5) // 收件人输入 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;收件人邮箱：&quot;) .width(90) .fontSize(14) .flexGrow(0) TextInput(&#123; placeholder: &quot;多个使用逗号分隔&quot;, text: this.rcptList &#125;) .onChange((value) =&gt; &#123; this.rcptList = value &#125;) .width(110) .fontSize(12) .flexGrow(1) &#125;.width(&#x27;100%&#x27;).padding(5) // 邮件标题输入 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;标题：&quot;) .width(50) .fontSize(14) .flexGrow(0) TextInput(&#123; text: this.mailTitle &#125;) .onChange((value) =&gt; &#123; this.mailTitle = value &#125;) .width(110) .fontSize(12) .flexGrow(1) &#125;.width(&#x27;100%&#x27;).padding(5) // 发件人邮箱输入 Flex(&#123; justifyContent: FlexAlign.Start, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;发件人邮箱：&quot;) .width(90) .fontSize(14) .flexGrow(0) TextInput(&#123; text: this.mailFrom &#125;) .onChange((value) =&gt; &#123; this.mailFrom = value &#125;) .width(110) .fontSize(12) .flexGrow(1) &#125;.width(&#x27;100%&#x27;).padding(5) // 邮件内容输入和发送按钮 Flex(&#123; justifyContent: FlexAlign.Start, direction: FlexDirection.Column, alignItems: ItemAlign.Center &#125;) &#123; Text(&quot;邮件内容：&quot;) .width(&#x27;100%&#x27;) .fontSize(14) TextArea(&#123; text: this.mailContent &#125;) .onChange((value) =&gt; &#123; this.mailContent = value &#125;) .width(&#x27;100%&#x27;) .height(120) .fontSize(12) Button(&quot;发送&quot;) .enabled(this.canSend) // 仅在登录成功后可用 .onClick(() =&gt; &#123; this.sendMail() &#125;) .width(80) .fontSize(14) &#125; .flexGrow(1) .width(&#x27;100%&#x27;) .padding(5) .height(&#x27;100%&#x27;) &#125; .width(&#x27;100%&#x27;) .justifyContent(FlexAlign.Start) .height(&#x27;100%&#x27;) .padding(10) &#125; .height(&#x27;100%&#x27;) &#125; // 创建新的TLSSocket实例 createNewSocket() &#123; if (tlsSocket) &#123; try &#123; tlsSocket.close(); &#125; catch (e) &#123;&#125; &#125; tlsSocket = socket.constructTLSSocketInstance(); this.bindLocal = false; &#125; // 绑定Socket到本地地址并设置监听器 async bindSocket() &#123; this.createNewSocket(); try &#123; let localAddress: LocalAddress = &#123; address: &quot;0.0.0.0&quot;, family: 1 &#125;; // 绑定到所有IPv4地址 await tlsSocket!.bind(localAddress); console.log(&quot;C: bind success&quot;); this.bindLocal = true; &#125; catch (e) &#123; console.error(`C: bind fail - $&#123;e.message || e&#125;`); &#125; // 监听服务器消息 tlsSocket!.on(&quot;message&quot;, (value: MessageValue) =&gt; &#123; this.isServerResponse = true; let msg = buf2String(value.message); console.log(`S: $&#123;msg&#125;`); &#125;); // 监听错误事件 tlsSocket!.on(&quot;error&quot;, (err) =&gt; &#123; console.error(`E: Socket 错误 - $&#123;err.message || err.code || &#x27;未知 TLS 错误&#x27;&#125;`); console.error(&quot;详细错误对象:&quot;, err); this.cleanupSocket(); &#125;); // 监听连接关闭事件 tlsSocket!.on(&quot;close&quot;, () =&gt; &#123; console.log(&quot;C: 连接已被服务器断开（可能是空闲超时）&quot;); console.log(&quot;C: 发送按钮已禁用，请重新点击&#x27;登录&#x27;或&#x27;发送&#x27;来重连&quot;); this.canSend = false; this.cleanupSocket(); &#125;); &#125; // 清理Socket资源 cleanupSocket() &#123; if (tlsSocket) &#123; try &#123; tlsSocket.close(); &#125; catch (e) &#123;&#125; tlsSocket = null; &#125; this.bindLocal = false; this.isServerResponse = false; &#125; // SMTP登录流程 async login() &#123; try &#123; this.cleanupSocket(); await this.bindSocket(); let serverAddress: ServerAddress = &#123; address: this.serverAddr, port: this.serverPort, family: 1 &#125;; // 配置TLS选项 const secureOptions: SecureOptions = &#123; protocols: [socket.Protocol.TLSv12, socket.Protocol.TLSv13], // 支持TLS 1.2和1.3 cipherSuite: &#x27;TLS_AES_128_GCM_SHA256:TLS_AES_256_GCM_SHA384:TLS_CHACHA20_POLY1305_SHA256&#x27; // 加密套件 &#125;; const connectOptions: ConnectOptions = &#123; address: serverAddress, secureOptions: secureOptions &#125;; // 连接SMTP服务器 console.log(`C: 正在连接 $&#123;this.serverAddr&#125;:$&#123;this.serverPort&#125; (TLS)...`); await tlsSocket!.connect(connectOptions); console.log(&quot;C: TLS 连接成功！&quot;); // 等待服务器欢迎消息（220） await this.wait4ServerResponse(10000); if (!this.isServerResponse) &#123; throw new Error(&quot;未收到 220 欢迎消息&quot;); &#125; // SMTP握手流程 await this.exeCmdAndWait4Response(&quot;EHLO harmonyos.next&quot;); // 发送EHLO命令 await this.exeCmdAndWait4Response(&quot;AUTH LOGIN&quot;); // 开始认证 // Base64编码的用户名和密码 let loginName = string2Base64(this.userName); await this.exeCmdAndWait4Response(loginName); let passWd = string2Base64(this.passwd); await this.exeCmdAndWait4Response(passWd); if (this.isServerResponse) &#123; // 简化判断（实际应检查235响应码） this.canSend = true; console.log(&quot;C: 登录成功！（235 Authentication successful）&quot;); console.log(&quot;C: 可以开始发送邮件&quot;); &#125; else &#123; throw new Error(&quot;登录失败，请检查邮箱/授权码&quot;); &#125; &#125; catch (e) &#123; console.error(`C: 登录失败 - $&#123;e.message || e&#125;`); this.cleanupSocket(); &#125; &#125; // 发送邮件 async sendMail() &#123; if (!this.canSend || !tlsSocket) &#123; console.log(&quot;C: 连接不可用，正在自动尝试重连...&quot;); await this.login(); if (!this.canSend) return; &#125; try &#123; console.log(&quot;C: 开始发送邮件...&quot;); // SMTP发送流程 await this.exeCmdAndWait4Response(`MAIL FROM:&lt;$&#123;this.mailFrom&#125;&gt;`); // 发件人 // 收件人列表（支持多个） let rcptMails = this.rcptList.split(&#x27;,&#x27;); for (let rcpt of rcptMails) &#123; rcpt = rcpt.trim(); if (rcpt) await this.exeCmdAndWait4Response(`RCPT TO:&lt;$&#123;rcpt&#125;&gt;`); &#125; await this.exeCmdAndWait4Response(&quot;DATA&quot;); // 准备发送数据 // 构建邮件头 let mailBody = `From: $&#123;this.mailFrom&#125;
`; mailBody += `To: $&#123;this.rcptList&#125;
`; mailBody += `Subject: =?utf-8?B?$&#123;string2Base64(this.mailTitle)&#125;?=
`; // Base64编码标题 mailBody += `Date: $&#123;new Date().toUTCString()&#125;
`; mailBody += `Content-Type: text/plain; charset=&quot;utf-8&quot;
`; mailBody += `Content-Transfer-Encoding: base64

`; mailBody += `$&#123;string2Base64(this.mailContent)&#125;
`; // Base64编码内容 mailBody += &quot;.
&quot;; // SMTP数据结束标记 // 分块发送邮件内容（避免大包） const chunkSize = 2048; for (let i = 0; i &lt; mailBody.length; i += chunkSize) &#123; const chunk = mailBody.substring(i, i + chunkSize); await tlsSocket!.send(chunk); console.log(`C: [chunk sent, length=$&#123;chunk.length&#125;]`); &#125; // 等待服务器确认 await this.wait4ServerResponse(15000); if (!this.isServerResponse) &#123; throw new Error(&quot;服务器未确认邮件接收&quot;); &#125; console.log(&quot;C: 邮件发送成功！连接保持打开，可继续发送下一封&quot;); &#125; catch (e) &#123; console.error(`C: 发送失败 - $&#123;e.message || e&#125;`); this.cleanupSocket(); &#125; &#125; // 执行SMTP命令并等待响应 async exeCmdAndWait4Response(cmd: string) &#123; if (!tlsSocket) &#123; throw new Error(&quot;Socket 未初始化&quot;); &#125; this.isServerResponse = false; let fullCmd = cmd + &quot;
&quot;; // SMTP命令以CRLF结束 try &#123; await tlsSocket.send(fullCmd); console.log(`C: $&#123;cmd&#125;`); &#125; catch (sendErr) &#123; console.error(`C: 发送命令失败 - $&#123;sendErr.message || sendErr&#125;`); throw new Error(sendErr.message || sendErr); &#125; await this.wait4ServerResponse(10000); &#125; // 等待服务器响应（轮询方式） async wait4ServerResponse(timeoutMs: number = 10000) &#123; const start = Date.now(); while (!this.isServerResponse) &#123; if (Date.now() - start &gt; timeoutMs) &#123; throw new Error(`等待响应超时 ($&#123;timeoutMs&#125;ms)`); &#125; await sleep(100); // 每100毫秒检查一次 &#125; &#125;&#125;// Base64 编码函数function string2Base64(src: string): string &#123; try &#123; let textEncoder = new util.TextEncoder(); let encodeValue = textEncoder.encodeInto(src); // 字符串转Uint8Array let tool = new util.Base64Helper(); return tool.encodeToStringSync(encodeValue); // Base64编码 &#125; catch (e) &#123; console.error(&quot;Base64 失败:&quot;, e); return &quot;&quot;; &#125;&#125;// ArrayBuffer 转字符串函数function buf2String(buf: ArrayBuffer): string &#123; try &#123; let msgArray = new Uint8Array(buf); let textDecoder = util.TextDecoder.create(&quot;utf-8&quot;); return textDecoder.decodeWithStream(msgArray); // UTF-8解码 &#125; catch (e) &#123; console.error(&quot;解码失败:&quot;, e); return &quot;[解码失败]&quot;; &#125;&#125;// 异步休眠函数function sleep(time: number) &#123; return new Promise&lt;void&gt;((resolve) =&gt; setTimeout(resolve, time));&#125; 天气 代码链接：https://pan.wo.cn/s/1X1A4u98932 提取码：FxuX 位置定位：https://developer.huawei.com/consumer/cn/doc/best-practices/bpta-positioning#section1774418211717 在module.json5中添加网络访问权限： &quot;requestPermissions&quot;: [ &#123; &quot;name&quot;: &quot;ohos.permission.INTERNET&quot; &#125;] utils/HttpUtil.ts // utils/HttpUtil.tsimport http from &#x27;@ohos.net.http&#x27;;import util from &#x27;@ohos.util&#x27;;interface ZlibModule &#123; unzip(data: ArrayBuffer, callback: (err: Error, result: ArrayBuffer) =&gt; void): void;&#125;declare function requireNapi(moduleName: string): ZlibModule;/** * 检查数据是否为 GZIP 格式 */function isGzipData(data: ArrayBuffer | Uint8Array): boolean &#123; const uint8Array = data instanceof Uint8Array ? data : new Uint8Array(data); return uint8Array.length &gt;= 2 &amp;&amp; uint8Array[0] === 0x1F &amp;&amp; uint8Array[1] === 0x8B;&#125;/** * 使用鸿蒙系统 zlib 解压 GZIP 数据 */async function ungzipData(compressedData: ArrayBuffer): Promise&lt;string&gt; &#123; return new Promise((resolve, reject) =&gt; &#123; try &#123; const zlib: ZlibModule = requireNapi(&#x27;zlib&#x27;); zlib.unzip(compressedData, (err: Error, result: ArrayBuffer) =&gt; &#123; if (err) &#123; reject(err); return; &#125; const decoder = new util.TextDecoder(&#x27;utf-8&#x27;); const uint8Result = new Uint8Array(result); const output = decoder.decodeWithStream(uint8Result); resolve(output); &#125;); &#125; catch (error) &#123; console.error(&#x27;zlib 加载失败&#x27;, error); reject(new Error(&#x27;zlib 解压失败&#x27;)); &#125; &#125;);&#125;/** * 网络请求工具类 - 使用 @ohos.net.http，支持 GZIP 自动解压或手动处理 * @param url 请求地址 * @returns 响应数据 */export function request&lt;T&gt;(url: string): Promise&lt;T&gt; &#123; return new Promise&lt;T&gt;((resolve, reject) =&gt; &#123; console.log(&#x27;发起请求:&#x27;, url); const httpRequest = http.createHttp(); httpRequest.request(url, &#123; method: http.RequestMethod.GET, header: &#123; &#x27;Accept-Encoding&#x27;: &#x27;gzip&#x27;, // 允许压缩 &#125; // 鸿蒙http模块不支持responseType参数 &#125;).then(response =&gt; &#123; console.log(&#x27;请求响应码:&#x27;, response.responseCode); console.log(&#x27;响应数据类型:&#x27;, typeof response.result); if (response.responseCode === 200) &#123; try &#123; let dataStr: string; // 处理数据的函数 const processData = () =&gt; &#123; try &#123; // 解析 JSON console.log(&#x27;尝试解析 JSON，数据前50字符:&#x27;, dataStr.substring(0, 50)); const result = JSON.parse(dataStr) as T; console.log(&#x27;JSON 解析成功&#x27;); resolve(result); &#125; catch (error) &#123; console.error(&#x27;处理响应失败:&#x27;, error); console.log(&#x27;原始数据前200:&#x27;, (response.result as string)?.substring(0, 200)); reject(new Error(&#x27;处理响应失败: &#x27; + error.message)); &#125; &#125;; if (typeof response.result === &#x27;string&#x27;) &#123; console.log(&#x27;收到字符串数据，长度:&#x27;, response.result.length); // 系统已自动解压，直接使用 dataStr = response.result; processData(); &#125; else if (response.result instanceof ArrayBuffer) &#123; // 如果是 ArrayBuffer，手动处理 console.log(&#x27;收到 ArrayBuffer 数据，长度:&#x27;, response.result.byteLength); const uint8 = new Uint8Array(response.result); if (isGzipData(uint8)) &#123; ungzipData(response.result).then(decompressed =&gt; &#123; dataStr = decompressed; // 继续处理逻辑 processData(); &#125;).catch((error: Error) =&gt; &#123; reject(new Error(&#x27;解压失败: &#x27; + error.message)); return; &#125;); return; // 等待异步操作完成 &#125; else &#123; const decoder = new util.TextDecoder(&#x27;utf-8&#x27;); dataStr = decoder.decodeWithStream(uint8); // 继续处理逻辑 processData(); &#125; &#125; else &#123; reject(new Error(&#x27;未知响应数据类型&#x27;)); return; &#125; // ArrayBuffer数据在各自的处理分支中调用processData() &#125; catch (error) &#123; console.error(&#x27;数据处理失败:&#x27;, error); reject(new Error(&#x27;数据处理失败: &#x27; + error.message)); &#125; &#125; else &#123; reject(new Error(`请求失败，状态码：$&#123;response.responseCode&#125;`)); &#125; &#125;).catch((error: Error) =&gt; &#123; console.error(&#x27;网络请求失败:&#x27;, error); reject(new Error(&#x27;网络请求失败: &#x27; + error.message)); &#125;).finally(() =&gt; &#123; httpRequest.destroy(); // 必须销毁 &#125;); &#125;);&#125; service/WeatherService.ts // service/WeatherService.tsimport &#123; DailyForecast, RealTimeWeather, WeatherResponse, LocationResponse, RealTimeWeatherResponse, DailyForecastResponse, LocationItem&#125; from &quot;../model/WeatherModel&quot;;import &#123; request &#125; from &quot;../utils/HttpUtil&quot;;// 和风天气API配置const API_KEY = &#x27;dc6b637284d547fb9427f5caf4475554&#x27;;const API_HOST = &#x27;https://q53yfrtevq.re.qweatherapi.com&#x27;; // 你的专属域名/** * 根据城市获取天气数据 * @param city 城市名称 */export async function getWeatherByCity(city: string): Promise&lt;WeatherResponse&gt; &#123; try &#123; // 1. 获取城市Location ID - 移除禁用压缩参数，让服务器正常 gzip，fetch 自动处理 const baseParams = `location=$&#123;encodeURIComponent(city)&#125;&amp;key=$&#123;API_KEY&#125;`; const locationUrl = `$&#123;API_HOST&#125;/geo/v2/city/lookup?$&#123;baseParams&#125;`; console.log(&#x27;请求位置URL:&#x27;, locationUrl); const locationRes = await request&lt;LocationResponse&gt;(locationUrl); console.log(&#x27;位置响应成功&#x27;); if (!locationRes.location || locationRes.location.length === 0) &#123; throw new Error(&#x27;未找到该城市的天气数据&#x27;); &#125; const locationId = locationRes.location[0].id; console.log(&#x27;找到城市ID:&#x27;, locationId, &#x27;城市名:&#x27;, locationRes.location[0].name); // 2. 获取实时天气 - 移除禁用压缩参数 const weatherParams = `location=$&#123;locationId&#125;&amp;key=$&#123;API_KEY&#125;`; const realTimeUrl = `$&#123;API_HOST&#125;/v7/weather/now?$&#123;weatherParams&#125;`; console.log(&#x27;请求实时天气URL:&#x27;, realTimeUrl); const realTimeRes = await request&lt;RealTimeWeatherResponse&gt;(realTimeUrl); console.log(&#x27;实时天气响应成功&#x27;); // 3. 获取未来3天预报 const dailyUrl = `$&#123;API_HOST&#125;/v7/weather/3d?$&#123;weatherParams&#125;`; console.log(&#x27;请求天气预报URL:&#x27;, dailyUrl); const dailyRes = await request&lt;DailyForecastResponse&gt;(dailyUrl); console.log(&#x27;天气预报响应成功&#x27;); // 数据转换（保持不变） const realTime: RealTimeWeather = &#123; temp: realTimeRes.now.temp, text: realTimeRes.now.text, windDir: realTimeRes.now.windDir, windScale: realTimeRes.now.windScale, humidity: realTimeRes.now.humidity, updateTime: realTimeRes.updateTime &#125;; const dailyForecasts: DailyForecast[] = dailyRes.daily.map((item: DailyForecast): DailyForecast =&gt; (&#123; fxDate: item.fxDate, tempMax: item.tempMax, tempMin: item.tempMin, textDay: item.textDay &#125;)); console.log(&#x27;数据处理完成&#x27;); return &#123; realTime, dailyForecasts &#125;; &#125; catch (error) &#123; console.error(&#x27;获取天气失败:&#x27;, error); throw new Error(error.message); &#125;&#125; model/WeatherModel.ts // model/WeatherModel.ts/** * 实时天气数据模型 */export interface RealTimeWeather &#123; temp: string; // 温度 text: string; // 天气状况（晴/雨/多云） windDir: string; // 风向 windScale: string; // 风力等级 humidity: string; // 湿度 updateTime: string; // 更新时间&#125;/** * 未来预报数据模型 */export interface DailyForecast &#123; fxDate: string; // 日期 tempMax: string; // 最高温 tempMin: string; // 最低温 textDay: string; // 白天天气状况&#125;/** * 天气响应体模型 */export interface WeatherResponse &#123; realTime: RealTimeWeather; dailyForecasts: DailyForecast[];&#125;/** * 位置查询响应模型 */export interface LocationItem &#123; id: string; name: string;&#125;export interface LocationResponse &#123; location: LocationItem[];&#125;/** * 实时天气响应模型 */export interface RealTimeWeatherResponse &#123; now: RealTimeWeather; updateTime: string;&#125;/** * 未来预报响应模型 */export interface DailyForecastResponse &#123; daily: DailyForecast[];&#125; pages/WeatherPage.ts import &#123; DailyForecast, RealTimeWeather &#125; from &#x27;../model/WeatherModel&#x27;;import &#123; getWeatherByCity &#125; from &#x27;../service/WeatherService&#x27;;@Entry@Componentstruct WeatherPage &#123; // 状态管理 @State private cityName: string = &#x27;北京&#x27;; // 默认查询北京 @State private inputCity: string = &#x27;&#x27;; @State private realTimeWeather: RealTimeWeather | null = null; @State private dailyForecasts: DailyForecast[] = []; @State private isLoading: boolean = false; @State private errorMsg: string = &#x27;&#x27;; // 页面加载时初始化数据 aboutToAppear() &#123; this.fetchWeatherData(this.cityName); &#125; build() &#123; Column() &#123; // 标题区域 Text(&#x27;鸿蒙天气&#x27;) .fontSize(28) .fontWeight(FontWeight.Bold) .margin(&#123; top: 20, bottom: 15 &#125;) .alignSelf(ItemAlign.Center); // 城市查询区域 Row(&#123; space: 10 &#125;) &#123; TextInput(&#123; placeholder: &#x27;请输入城市名称...&#x27;, text: this.inputCity &#125;) .onChange((value: string) =&gt; &#123; this.inputCity = value; &#125;) .width(&#x27;70%&#x27;) .height(45) .border(&#123; width: 1, radius: 8, color: &#x27;#E5E5E5&#x27; &#125;) .padding(&#123; left: 10 &#125;); Button(&#x27;查询&#x27;) .width(&#x27;20%&#x27;) .height(45) .backgroundColor(&#x27;#007DFF&#x27;) .fontColor(Color.White) .borderRadius(8) .onClick(() =&gt; &#123; if (this.inputCity.trim()) &#123; this.fetchWeatherData(this.inputCity.trim()); &#125; &#125;); &#125; .margin(&#123; bottom: 20 &#125;) .padding(&#123; left: 15, right: 15 &#125;); // 加载状态提示 if (this.isLoading) &#123; LoadingProgress() .width(40) .height(40) .margin(&#123; bottom: 20 &#125;) .alignSelf(ItemAlign.Center); &#125; // 错误提示 if (this.errorMsg) &#123; Text(this.errorMsg) .fontSize(14) .fontColor(&#x27;#FF4D4F&#x27;) .margin(&#123; bottom: 20 &#125;) .alignSelf(ItemAlign.Center); &#125; // 实时天气展示 if (this.realTimeWeather) &#123; Column() &#123; Text(`$&#123;this.cityName&#125; 实时天气`) .fontSize(20) .fontWeight(FontWeight.Medium) .margin(&#123; bottom: 10 &#125;); Row(&#123; space: 20 &#125;) &#123; Text(`$&#123;this.realTimeWeather.temp&#125;°C`) .fontSize(48) .fontWeight(FontWeight.Bold); Column() &#123; Text(this.realTimeWeather.text) .fontSize(18) .margin(&#123; bottom: 5 &#125;); Text(`更新时间：$&#123;this.formatTime(this.realTimeWeather.updateTime)&#125;`) .fontSize(12) .fontColor(&#x27;#999&#x27;); &#125; &#125; .margin(&#123; bottom: 15 &#125;); // 天气详情 Grid() &#123; GridItem() &#123; this.buildWeatherInfoItem(&#x27;风向&#x27;, `$&#123;this.realTimeWeather.windDir&#125;`); &#125; GridItem() &#123; this.buildWeatherInfoItem(&#x27;风力&#x27;, `$&#123;this.realTimeWeather.windScale&#125;级`); &#125; GridItem() &#123; this.buildWeatherInfoItem(&#x27;湿度&#x27;, `$&#123;this.realTimeWeather.humidity&#125;%`); &#125; &#125; .columnsTemplate(&#x27;1fr 1fr 1fr&#x27;) .width(&#x27;90%&#x27;) .margin(&#123; bottom: 30 &#125;); &#125; .padding(20) .backgroundColor(Color.White) .borderRadius(12) .shadow(&#123; radius: 4, color: &#x27;#00000010&#x27;, offsetX: 0, offsetY: 2 &#125;) .width(&#x27;90%&#x27;) .alignSelf(ItemAlign.Center); &#125; // 未来预报展示 if (this.dailyForecasts.length &gt; 0) &#123; Text(&#x27;未来3天预报&#x27;) .fontSize(18) .fontWeight(FontWeight.Medium) .margin(&#123; bottom: 10, top: 20 &#125;) .alignSelf(ItemAlign.Start) .padding(&#123; left: 15 &#125;); List(&#123; space: 10 &#125;) &#123; ForEach(this.dailyForecasts, (item: DailyForecast) =&gt; &#123; ListItem() &#123; Row(&#123; space: 10 &#125;) &#123; Text(item.fxDate) .width(80) .fontSize(14); Text(item.textDay) .width(60) .fontSize(14); Text(`↑$&#123;item.tempMax&#125;°C`) .width(50) .fontSize(14) .fontColor(&#x27;#FF4D4F&#x27;); Text(`↓$&#123;item.tempMin&#125;°C`) .width(50) .fontSize(14) .fontColor(&#x27;#007DFF&#x27;); &#125; .padding(15) .backgroundColor(Color.White) .borderRadius(8) .width(&#x27;100%&#x27;); &#125; &#125;) &#125; .padding(&#123; left: 15, right: 15 &#125;) .width(&#x27;100%&#x27;); &#125; &#125; .width(&#x27;100%&#x27;) .height(&#x27;100%&#x27;) .backgroundColor(&#x27;#F8F8F8&#x27;); &#125; /** * 构建天气信息子项 */ @Builder private buildWeatherInfoItem(title: string, value: string) &#123; Column() &#123; Text(title) .fontSize(14) .fontColor(&#x27;#999&#x27;) .margin(&#123; bottom: 5 &#125;); Text(value) .fontSize(16) .fontWeight(FontWeight.Medium); &#125; .alignItems(HorizontalAlign.Center); &#125; /** * 格式化时间 */ private formatTime(timeStr: string): string &#123; return timeStr.replace(&#x27;T&#x27;, &#x27; &#x27;).substring(0, 16); &#125; /** * 获取天气数据 */ private async fetchWeatherData(city: string) &#123; this.isLoading = true; this.errorMsg = &#x27;&#x27;; try &#123; const weatherData = await getWeatherByCity(city); this.cityName = city; this.realTimeWeather = weatherData.realTime; this.dailyForecasts = weatherData.dailyForecasts; &#125; catch (error) &#123; this.errorMsg = error.message || &#x27;获取天气数据失败，请重试&#x27;; console.error(&#x27;获取天气失败：&#x27;, error); &#125; finally &#123; this.isLoading = false; &#125; &#125;&#125;
